import { fileURLToPath } from "node:url";

import {
  sendWithVc,
} from "portauth-a2a";

const DEFAULTS = {
  issuerUrl: process.env.ISSUER_URL || "http://localhost:3100",
  engineUrl: process.env.ENGINE_URL || "http://localhost:3200",
  receiverUrl: process.env.A2A_RECEIVER_URL || "http://localhost:3300",
  issuerKey: process.env.ISSUER_KEY || "dev-issuer-key-change-me",
  engineKey: process.env.ENGINE_KEY || "dev-engine-key-change-me",
  issuerIdForEngine: process.env.ISSUER_ID_FOR_ENGINE || "http://portauth-issuer:3100",
  receiverBearerToken: process.env.A2A_RECEIVER_BEARER_TOKEN || null,
};

const PRESENTER_ID = process.env.PRESENTER_ID || "agent:customer-finance-1";

export const scenarios = Object.freeze({
  allow: {
    text: "Pay my electric bill for 2400 USD.",
    requestContext: {
      action: "payments:bill_pay",
      resource: "urn:bank:utilities/electric",
      claimAmount: 2400,
      currency: "USD",
      recipientId: "utilities",
      geoRegion: "US",
    },
    expect: "allow",
  },
  "deny-amount": {
    text: "Pay my electric bill for 3000 USD.",
    requestContext: {
      action: "payments:bill_pay",
      resource: "urn:bank:utilities/electric",
      claimAmount: 3000,
      currency: "USD",
      recipientId: "utilities",
      geoRegion: "US",
    },
    expect: "deny",
  },
  "deny-recipient": {
    text: "Send 200 USD to an unapproved recipient.",
    requestContext: {
      action: "payments:bill_pay",
      resource: "urn:bank:misc/unapproved",
      claimAmount: 200,
      currency: "USD",
      recipientId: "gambling",
      geoRegion: "US",
    },
    expect: "deny",
  },
  "deny-geo": {
    text: "Pay a European utility bill for 100 USD.",
    requestContext: {
      action: "payments:bill_pay",
      resource: "urn:bank:utilities/eu",
      claimAmount: 100,
      currency: "USD",
      recipientId: "utilities",
      geoRegion: "EU",
    },
    expect: "deny",
  },
});

export async function runScenario(name = "allow", options = {}) {
  const config = { ...DEFAULTS, ...options };
  const scenario = scenarios[name];
  if (!scenario) {
    throw new Error(`unknown scenario '${name}'. Valid scenarios: ${Object.keys(scenarios).join(", ")}`);
  }

  await registerIssuer(config);
  const credential = await issueCredential(config);
  const idempotencyKey = `a2a-reference-${name}-${Date.now()}`;
  const result = await sendWithVc({
    receiverUrl: config.receiverUrl,
    credential,
    vcFormat: "tier1-jwt",
    presenterId: PRESENTER_ID,
    text: scenario.text,
    requestContext: scenario.requestContext,
    idempotencyKey,
    authorization: config.receiverBearerToken ? `Bearer ${config.receiverBearerToken}` : undefined,
    fetchImpl: config.fetchImpl || globalThis.fetch,
  });

  return {
    scenario: name,
    expected: scenario.expect,
    status: result.status,
    ok: result.ok,
    body: result.body,
  };
}

export async function registerIssuer({
  engineUrl = DEFAULTS.engineUrl,
  engineKey = DEFAULTS.engineKey,
  issuerIdForEngine = DEFAULTS.issuerIdForEngine,
  fetchImpl = globalThis.fetch,
} = {}) {
  const body = {
    issuerId: issuerIdForEngine,
    trustTier: 1,
    trustedForPermissions: ["payments:bill_pay"],
    label: "A2A Reference Presenter Issuer",
    jwksUri: `${issuerIdForEngine}/.well-known/jwks.json`,
  };
  const created = await httpJson(fetchImpl, "POST", `${engineUrl}/admin/issuers`, body, engineKey);
  if (created.ok || created.status === 201) return;
  if (created.status !== 409) {
    throw new Error(`issuer registration failed: ${created.status} ${JSON.stringify(created.body)}`);
  }

  const list = await httpJson(fetchImpl, "GET", `${engineUrl}/admin/issuers`, null, engineKey);
  const existing = (list.body?.issuers || []).find((issuer) => issuer.issuer_id === issuerIdForEngine);
  const merged = Array.from(new Set([...(existing?.trusted_for_permissions || []), "payments:bill_pay"]));
  const updated = await httpJson(fetchImpl, "PUT", `${engineUrl}/admin/issuers/${encodeURIComponent(issuerIdForEngine)}`, {
    trustedForPermissions: merged,
  }, engineKey);
  if (!updated.ok) throw new Error(`issuer permission update failed: ${updated.status} ${JSON.stringify(updated.body)}`);
}

export async function issueCredential({
  issuerUrl = DEFAULTS.issuerUrl,
  issuerKey = DEFAULTS.issuerKey,
  fetchImpl = globalThis.fetch,
} = {}) {
  const response = await httpJson(fetchImpl, "POST", `${issuerUrl}/credentials/issue`, {
    agentId: PRESENTER_ID,
    permissions: ["payments:bill_pay"],
    constraints: [
      { type: "NumericLimitConstraint", field: "core.amount", operator: "lte", value: 2500, currency: "USD" },
      { type: "EnumeratedListConstraint", field: "core.recipient_id", allowed: ["utilities", "telco", "mortgage"] },
      { type: "EnumeratedListConstraint", field: "core.geo_region", allowed: ["US"] },
    ],
  }, issuerKey);
  if (!response.ok) throw new Error(`credential issue failed: ${response.status} ${JSON.stringify(response.body)}`);
  return response.body.credential;
}

async function httpJson(fetchImpl, method, url, body, bearer) {
  const resp = await fetchImpl(url, {
    method,
    headers: {
      Accept: "application/json",
      "Content-Type": "application/json",
      ...(bearer ? { Authorization: `Bearer ${bearer}` } : {}),
    },
    body: body ? JSON.stringify(body) : undefined,
  });
  const text = await resp.text();
  let parsed = null;
  try {
    parsed = text ? JSON.parse(text) : null;
  } catch (_) {
    parsed = { raw: text };
  }
  return { ok: resp.ok, status: resp.status, body: parsed };
}

const isCli = process.argv[1] === fileURLToPath(import.meta.url);
if (isCli) {
  const scenario = process.argv[2] || "allow";
  const result = await runScenario(scenario);
  console.log(JSON.stringify(result, null, 2));
  const gotAllow = result.ok && result.body?.task?.status?.state === "TASK_STATE_COMPLETED";
  const expectedOk = result.expected === "allow";
  process.exit(gotAllow === expectedOk ? 0 : 1);
}
